function zigzagLevelOrder(root) {
    if (!root) return [];

    const result = [];
    let queue = [root];
    let zigzag = false;

    while (queue.length) {
        const level = [];
        const queueLen = queue.length;
        const tempQueue = [];

        for (let i = 0; i < queueLen; i++) {
            const node = queue[i];

            if (zigzag) level.unshift(node.val);
            else level.push(node.val);

            if (node.left) tempQueue.push(node.left);
            if (node.right) tempQueue.push(node.right);
